sql:
SELECT date, AVG(mortgage15us) AS average_rate
FROM mortgage_rates
GROUP BY date;

SELECT 
  (SELECT MIN(mortgage15us) FROM mortgage_rates) AS min_interest_rate,
  (SELECT MAX(gdp) FROM economic_indicators) AS max_gdp;

SELECT 
  (SELECT MIN(mortgage30us) FROM mortgage_rates) AS min_30_year_mortgage_rate,
  (SELECT MIN(inflation_rate) FROM economic_indicators) AS min_inflation_rate;

external_knowledge:
- 'mortgage type' refers to the type of mortgage such as fixed-rate or variable-rate; 
- 'economic indicators' refer to the economic metrics such as GDP, inflation rate, and employment rate; 
- 'average mortgage rates' are calculated based on historical mortgage rate data; 
- 'average economic indicator values' are calculated based on historical economic data.

